#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10,B=350;

struct Seg{
    int l,r,id;
}seg[N];

int n,m,k,a[N],f[N],g[N],s[1<<14];
long long ans[N];
vector<int> v;
vector<Seg> sf[N],sg[N];

bool cmp(Seg x,Seg y){
    if(x.l/B==y.l/B)
        return x.r<y.r;
    return x.l/B<y.l/B;
}

int ones(int x){
    int res=0;
    while(x)
        res++,x-=(x&(-x));
    return res;
}

int main(){
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=m;i++){
        scanf("%d%d",&seg[i].l,&seg[i].r);
        seg[i].id=i;
    }
    for(int i=0;i<1<<14;i++)
        if(ones(i)==k)
            v.push_back(i);
    for(int i=1;i<=n;i++){
        f[i]=s[a[i]];
        for(int j:v)
            s[a[i]^j]++;
    }
    memset(s,0,sizeof(s));
    for(int i=n;i;i--){
        g[i]=s[a[i]];
        for(int j:v)
            s[a[i]^j]++;
    }
    memset(s,0,sizeof(s));
    sort(seg+1,seg+m+1,cmp);
    int l=1,r=0;
    for(int i=1;i<=m;i++){
        if(r<seg[i].r)
            sf[l].push_back({r+1,seg[i].r,seg[i].id});
        if(r>seg[i].r)
            sf[l].push_back({seg[i].r+1,r,-seg[i].id});
        r=seg[i].r;
        if(l>seg[i].l)
            sg[r].push_back({seg[i].l,l-1,seg[i].id});
        if(l<seg[i].l)
            sg[r].push_back({l,seg[i].l-1,-seg[i].id});
        l=seg[i].l;
    }
    for(int i=1;i<=n;i++){
        for(Seg j:sf[i]){
            for(int k=j.l;k<=j.r;k++){
                if(j.id>0)
                    ans[j.id]+=f[k]-s[a[k]];
                else
                    ans[-j.id]-=f[k]-s[a[k]];
            }
        }
        for(int j:v)
            s[a[i]^j]++;
    }
    memset(s,0,sizeof(s)); 
    for(int i=n;i;i--){
        for(Seg j:sg[i]){
            for(int k=j.l;k<=j.r;k++){
                if(j.id>0)
                    ans[j.id]+=g[k]-s[a[k]];
                else
                    ans[-j.id]-=g[k]-s[a[k]];
            }
        }
        for(int j:v)
            s[a[i]^j]++;
    }
    for(int i=1;i<=m;i++)
        ans[seg[i].id]+=ans[seg[i-1].id];
    for(int i=1;i<=m;i++)
        printf("%lld\n",ans[i]);
    return 0;
}
